#!/bin/bash

# Create a temp file with predictable name.
tmpfile=$(mktemp /tmp/${0##*/}-$$.tmp) || exit 1

# Write data to the tmp file.
echo "Hello World" > $tmpfile

# Process the data and read results from it.
cat $tmpfile | grep -v "^#" >> $tmpfile

# Read the results of processing.
cat $tmpfile

# Delete temp files.
rm $tmpfile